<div class="page-title-row"><div><h1>Corrective Actions</h1><p class="text-muted mb-0">Track deficiencies from inspections through verified resolution.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><div class="portal-card"><h2>New Action</h2><form method="post" action="/portal/corrective-actions" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Title</label><input name="title" class="form-control" required></div><div class="col-6"><label class="form-label">Job ID</label><input name="job_id" type="number" class="form-control"></div><div class="col-6"><label class="form-label">Inspection ID</label><input name="inspection_id" type="number" class="form-control"></div><div class="col-6"><label class="form-label">Severity</label><select name="severity" class="form-select"><option>low</option><option selected>medium</option><option>high</option><option>critical</option></select></div><div class="col-6"><label class="form-label">Due</label><input name="due_at" type="datetime-local" class="form-control"></div><div class="col-12"><label class="form-label">Assign to</label><select name="assigned_user_id" class="form-select"><option value="">Unassigned</option><?php foreach($users as $u):?><option value="<?=$u['id']?>"><?=e($u['name'])?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Description</label><textarea name="description" class="form-control" rows="4"></textarea></div><div class="col-12"><button class="btn btn-primary w-100">Create Action</button></div></form></div></div><div class="col-xl-8"><div class="portal-card"><div class="table-responsive"><table class="table portal-table align-middle"><thead><tr><th>Action</th><th>Severity</th><th>Assigned</th><th>Due</th><th>Status</th><th>Escalation</th><th></th></tr></thead><tbody><?php foreach($actions as $a):?><tr><td><strong><?=e($a['title'])?></strong><small><?=e($a['description']??'')?><?=$a['job_number']?' · Job '.e($a['job_number']):''?></small></td><td><span class="badge text-bg-<?=$a['severity']==='critical'?'danger':($a['severity']==='high'?'warning':'secondary')?>"><?=e($a['severity'])?></span></td><td><?=e($a['assigned_name']??'Unassigned')?></td><td><?=e($a['due_at']??'—')?></td><td><?=e($a['status'])?></td><td><?php if((int)($a['escalation_level']??0)>0):?><span class="badge text-bg-danger">Level <?=e($a['escalation_level'])?></span><?php else:?><span class="text-muted">None</span><?php endif?></td><td><form method="post" action="/portal/corrective-actions/<?=$a['id']?>" class="d-flex gap-1"><?=csrf_field()?><select name="status" class="form-select form-select-sm"><option>open</option><option>assigned</option><option>in_progress</option><option>verified</option><option>closed</option></select><button class="btn btn-sm btn-outline-primary">Update</button></form></td></tr><?php endforeach?><?php if(!$actions):?><tr><td colspan="7" class="text-center text-muted py-5">No corrective actions.</td></tr><?php endif?></tbody></table></div></div></div></div>
